#include <stdio.h>
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int special[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &special[i]);
    }
    int robots[M];
    for (int i = 0; i < M; i++) {
        scanf("%d", &robots[i]);
    }
    int count = 0;
    for (int t = 0; t < N; t++) {
        int allSpecial = 1;
        for (int i = 0; i < M; i++) {
            if (!special[(robots[i] + t) % N]) {
                allSpecial = 0;
                break;
            }
        }
        if (allSpecial) {
            count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

