code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int[] special = new int[N];
        for (int i = 0; i < N; i++) {
            special[i] = sc.nextInt();
        }
        int[] robots = new int[M];
        for (int i = 0; i < M; i++) {
            robots[i] = sc.nextInt();
        }
        int count = 0;
        for (int t = 0; t < N; t++) {
            int allSpecial = 1;
            for (int i = 0; i < M; i++) {
                if (special[(robots[i] + t) % N] == 0) {
                    allSpecial = 0;
                    break;
                }
            }
            if (allSpecial == 1) {
                count++;
            }
        }
        System.out.println(count);
    }
}

